const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="brevo"',perPage:1},headers:pbH,json:true});
const brevo=(s.items&&s.items[0]&&s.items[0].value)||{};
const listId=brevo.list_id;
if(listId==null) throw new Error('settings.brevo.list_id is not set — set your Brevo newsletter list id first.');
const incoming=($('Webhook').first().json.body)||{};
let filter='(verification_status="verified" || verification_status="catch_all" || verification_status="mx_only") && blocklisted!=true';
if(incoming.filter) filter='('+filter+') && ('+incoming.filter+')';
let rows=[]; let page=1;
while(true){ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter,expand:'club',perPage:500,page},headers:pbH,json:true}); for(const c of (r.items||[])){ const club=(c.expand&&c.expand.club)||{}; rows.push({email:c.email, attributes:{FIRSTNAME:c.name||'', CLUB_NAME:(club.name_en||club.name||''), COUNTRY:club.country||'', CITY:club.city||'', QUALITY:c.quality||''}}); } if(page>=(r.totalPages||1))break; page++; }
// --- job_runs: open the run ---
const sd=$getWorkflowStaticData('global'); const now=new Date().toISOString();
let jobId=''; try{ const j=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/job_runs/records',headers:pbH,body:{kind:'sync-brevo',label:'Sync to Brevo',status:'running',total:rows.length,processed:0,started:now},json:true}); jobId=j.id; }catch(e){}
sd.syncJobId=jobId; sd.syncTotal=rows.length;
const elig={}; for(const r of rows){ if(r.email) elig[String(r.email).trim().toLowerCase()]=1; } sd.eligible=elig; sd.syncListId=Number(listId); sd.syncRemoved=0; sd.syncCaptured=0; sd.syncMembers=0;
const out=[]; for(let i=0;i<rows.length;i+=1000){ out.push({json:{listIds:[Number(listId)],updateExistingContacts:true,jsonBody:rows.slice(i,i+1000)}}); }
if(!rows.length && jobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+jobId,headers:pbH,body:{status:'done',finished:now,processed:0,message:'No deliverable contacts to push'},json:true}); }catch(e){} sd.syncJobId=''; }
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const chunks=$('Build payload').all();
let pushed=0; for(const it of chunks){ pushed += ((it.json&&it.json.jsonBody)||[]).length; }
const now=new Date().toISOString();
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="brevo"',perPage:1},headers:pbH,json:true}); const rec=s.items&&s.items[0]; if(rec){ const v=rec.value||{}; v.last_sync=now; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/settings/records/'+rec.id,headers:pbH,body:{value:v},json:true}); } }catch(e){}
const sd=$getWorkflowStaticData('global');
const removed=sd.syncRemoved||0, captured=sd.syncCaptured||0;
if(sd.syncJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.syncJobId,headers:pbH,body:{status:'done',finished:now,processed:pushed,total:(sd.syncTotal||pushed),message:'Pushed '+pushed+' · removed '+removed+' · blocklist-captured '+captured},json:true}); }catch(e){} sd.syncJobId=''; }
return [{json:{pushed,removed,captured}}];

const cnt=Number(($json&&$json.count)||0);
const path=((($('After push').first()||{}).json)||{}).path;
const pages=Math.ceil(cnt/500);
const out=[]; for(let i=0;i<pages;i++){ out.push({json:{path, offset:i*500}}); }
if(!out.length) out.push({json:{path, offset:0}});
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const pages=$input.all();
const members=new Map();
for(const p of pages){ const cs=(p.json&&p.json.contacts)||[]; for(const c of cs){ if(c&&c.email){ members.set(String(c.email).trim().toLowerCase(), c.emailBlacklisted===true); } } }
const sd=$getWorkflowStaticData('global');
const eligible=sd.eligible||{}; const listId=sd.syncListId;
// capture blocklist: members Brevo flags -> mark in our DB (if not already)
const black=[...members.entries()].filter(function(e){return e[1];}).map(function(e){return e[0];});
let captured=0;
for(let i=0;i<black.length;i+=25){ await Promise.all(black.slice(i,i+25).map(async function(e){ try{ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:'email="'+e+'"',perPage:1,fields:'id,blocklisted'},headers:pbH,json:true}); const rec=r.items&&r.items[0]; if(rec&&rec.blocklisted!==true){ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+rec.id,headers:pbH,body:{blocklisted:true},json:true}); captured++; } }catch(e2){} }.bind(this))); }
// removals: list members no longer eligible
const toRemove=[...members.keys()].filter(function(e){return !eligible[e];});
sd.syncMembers=members.size; sd.syncRemoved=toRemove.length; sd.syncCaptured=captured;
const out=[];
for(let i=0;i<toRemove.length;i+=150){ out.push({json:{listId, emails:toRemove.slice(i,i+150)}}); }
if(!out.length) out.push({json:{listId, emails:[]}});
return out;
